content.content:
  1→/* ─── Dashboard Briefing ─── */
  2→
  3→.dashboard-briefing {
  4→    background: var(--bg-card);
  5→    border: 1px solid var(--border-card);
  6→    border-left: 3px solid var(--accent-amber);
  7→    border-radius: 14px;
  8→    box-shadow: var(--shadow-card-sm);
  9→    width: 100%;
 10→    margin-bottom: 16px;
 11→    overflow: hidden;
 12→}
 13→
 14→/* ─── Header ─── */
 15→
 16→.dashboard-briefing-header {
 17→    display: flex;
 18→    align-items: center;
 19→    justify-content: space-between;
 20→    padding: 14px 20px 0;
 21→}
 22→
 23→.dashboard-briefing-header-left {
 24→    display: flex;
 25→    align-items: center;
 26→    gap: 10px;
 27→}
 28→
 29→.dashboard-briefing-title {
 30→    font-family: 'Playfair Display', serif;
 31→    font-size: 15px;
 32→    font-weight: 600;
 33→    color: var(--text-primary, #1a1a1a);
 34→    margin: 0;
 35→}
 36→
 37→.dashboard-briefing-date {
 38→    font-family: 'Outfit', sans-serif;
 39→    font-size: 12px;
 40→    color: var(--text-secondary, #a1a1aa);
 41→    font-weight: 400;
 42→}
 43→
 44→.dashboard-briefing-toggle {
 45→    background: none;
 46→    border: none;
 47→    cursor: pointer;
 48→    color: var(--text-secondary, #a1a1aa);
 49→    padding: 4px;
 50→    border-radius: 6px;
 51→    display: flex;
 52→    align-items: center;
 53→    justify-content: center;
 54→    transition: background 0.15s ease, color 0.15s ease, transform 0.2s ease;
 55→}
 56→
 57→.dashboard-briefing-toggle:hover {
 58→    background: rgba(0, 0, 0, 0.05);
 59→    color: var(--text-primary, #1a1a1a);
 60→}
 61→
 62→.dashboard-briefing-toggle.is-collapsed {
 63→    transform: rotate(-90deg);
 64→}
 65→
 66→/* ─── Content (stacked layout) ─── */
 67→
 68→.dashboard-briefing-body {
 69→    display: flex;
 70→    flex-direction: column;
 71→    padding: 14px 20px 16px;
 72→    gap: 0;
 73→}
 74→
 75→/* ─── Divider ─── */
 76→
 77→.dashboard-divider {
 78→    height: 1px;
 79→    background: var(--border-card);
 80→    margin: 12px 0;
 81→}
 82→
 83→/* ─── Recap Section v2 ─── */
 84→
 85→.dashboard-recap-v2 {
 86→    display: flex;
 87→    flex-direction: column;
 88→    gap: 12px;
 89→}
 90→
 91→.recap-encouragement {
 92→    font-family: 'Lora', serif;
 93→    font-style: italic;
 94→    font-size: 13.5px;
 95→    color: var(--text-secondary, #a1a1aa);
 96→    margin: 0;
 97→    line-height: 1.5;
 98→}
 99→
100→/* ─── Stat Tiles Grid ─── */
101→
102→.recap-tiles-grid {
103→    display: grid;
104→    grid-template-columns: repeat(4, 1fr);
105→    gap: 8px;
106→}
107→
108→.recap-tile {
109→    display: flex;
110→    flex-direction: column;
111→    align-items: center;
112→    gap: 2px;
113→    padding: 12px 6px 10px;
114→    background: var(--bg-secondary, #f5f5f5);
115→    border-radius: 10px;
116→    transition: background 0.15s ease, transform 0.15s ease;
117→}
118→
119→.recap-tile:hover {
120→    background: var(--bg-hover, #ebebeb);
121→    transform: translateY(-1px);
122→}
123→
124→.recap-tile-icon {
125→    color: var(--accent-amber, #f59e0b);
126→    opacity: 0.8;
127→    margin-bottom: 2px;
128→}
129→
130→.recap-tile-value {
131→    font-family: 'Playfair Display', serif;
132→    font-size: 22px;
133→    font-weight: 700;
134→    color: var(--text-primary, #1a1a1a);
135→    font-variant-numeric: tabular-nums;
136→    line-height: 1.2;
137→}
138→
139→.recap-tile-label {
140→    font-family: 'Outfit', sans-serif;
141→    font-size: 11px;
142→    text-transform: lowercase;
143→    color: var(--text-muted, #9ca3af);
144→    letter-spacing: 0.3px;
145→}
146→
147→.recap-tile-micro {
148→    font-family: 'Lora', serif;
149→    font-size: 10px;
150→    font-style: italic;
151→    color: var(--accent-amber, #f59e0b);
152→    margin-top: 2px;
153→    text-align: center;
154→    line-height: 1.3;
155→}
156→
157→/* ─── Best Post Card ─── */
158→
159→.recap-best-post {
160→    display: flex;
161→    flex-direction: column;
162→    gap: 4px;
163→    padding: 12px 14px;
164→    background: linear-gradient(135deg, rgba(245, 158, 11, 0.08) 0%, rgba(245, 158, 11, 0.03) 100%);
165→    border: 1px solid rgba(245, 158, 11, 0.15);
166→    border-radius: 10px;
167→    cursor: pointer;
168→    transition: transform 0.15s ease, box-shadow 0.15s ease;
169→}
170→
171→.recap-best-post:hover {
172→    transform: translateY(-1px);
173→    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.12);
174→}
175→
176→.recap-best-post-badge {
177→    font-family: 'Outfit', sans-serif;
178→    font-size: 10px;
179→    font-weight: 600;
180→    text-transform: uppercase;
181→    letter-spacing: 0.5px;
182→    color: var(--accent-amber, #f59e0b);
183→    display: flex;
184→    align-items: center;
185→    gap: 4px;
186→}
187→
188→.recap-best-post-title {
189→    font-family: 'Lora', serif;
190→    font-size: 14px;
191→    color: var(--text-primary, #1a1a1a);
192→    line-height: 1.4;
193→    display: -webkit-box;
194→    -webkit-line-clamp: 2;
195→    -webkit-box-orient: vertical;
196→    overflow: hidden;
197→}
198→
199→.recap-best-post-stats {
200→    font-family: 'Outfit', sans-serif;
201→    font-size: 11px;
202→    color: var(--text-secondary, #a1a1aa);
203→}
204→
205→/* ─── Community Highlights ─── */
206→
207→.recap-community {
208→    display: flex;
209→    flex-direction: column;
210→    gap: 8px;
211→}
212→
213→.recap-community-label {
214→    font-family: 'Outfit', sans-serif;
215→    font-size: 11px;
216→    font-weight: 600;
217→    text-transform: uppercase;
218→    letter-spacing: 0.3px;
219→    color: var(--text-secondary, #a1a1aa);
220→}
221→
222→.recap-community-item {
223→    display: flex;
224→    align-items: center;
225→    gap: 8px;
226→}
227→
228→.recap-community-avatar {
229→    width: 22px;
230→    height: 22px;
231→    border-radius: 50%;
232→    object-fit: cover;
233→    flex-shrink: 0;
234→}
235→
236→.recap-community-text {
237→    font-family: 'Outfit', sans-serif;
238→    font-size: 13px;
239→    color: var(--text-primary, #1a1a1a);
240→    line-height: 1.4;
241→}
242→
243→.recap-community-text strong {
244→    font-weight: 600;
245→}
246→
247→.recap-community-clickable {
248→    cursor: pointer;
249→    padding: 4px 6px;
250→    margin: -4px -6px;
251→    border-radius: 8px;
252→    transition: background 0.15s ease;
253→}
254→
255→.recap-community-clickable:hover {
256→    background: var(--bg-hover, #ebebeb);
257→}
258→
259→/* ─── Prompt Section ─── */
260→
261→.dashboard-prompt {
262→    display: flex;
263→    flex-direction: column;
264→    gap: 10px;
265→}
266→
267→.dashboard-prompt-header {
268→    display: flex;
269→    align-items: center;
270→    gap: 8px;
271→}
272→
273→.dashboard-prompt-icon {
274→    opacity: 0.7;
275→    color: var(--accent-amber, #f59e0b);
276→    flex-shrink: 0;
277→}
278→
279→.dashboard-prompt-label {
280→    font-family: 'Outfit', sans-serif;
281→    font-size: 11px;
282→    font-weight: 600;
283→    text-transform: uppercase;
284→    letter-spacing: 0.5px;
285→    color: var(--text-secondary, #a1a1aa);
286→}
287→
288→.dashboard-prompt-category {
289→    font-size: 11px;
290→    padding: 2px 8px;
291→    border-radius: 10px;
292→    background: rgba(212, 168, 83, 0.12);
293→    color: var(--accent-amber, #f59e0b);
294→    margin-left: auto;
295→    font-weight: 500;
296→}
297→
298→.dashboard-prompt-text {
299→    font-family: 'Lora', serif;
300→    font-size: 18px;
301→    font-weight: 600;
302→    line-height: 1.6;
303→    margin: 0;
304→    color: var(--text-primary, #1a1a1a);
305→    border-left: 3px solid var(--accent-amber, #f59e0b);
306→    padding-left: 14px;
307→}
308→
309→.dashboard-prompt-footer {
310→    display: flex;
311→    align-items: center;
312→    justify-content: space-between;
313→    gap: 12px;
314→    margin-top: 2px;
315→    flex-wrap: wrap;
316→}
317→
318→.dashboard-prompt-write-btn {
319→    padding: 10px 24px;
320→    border-radius: 20px;
321→    border: none;
322→    background: var(--accent-amber, #f59e0b);
323→    color: #fff;
324→    font-family: 'Outfit', sans-serif;
325→    font-size: 13px;
326→    font-weight: 600;
327→    cursor: pointer;
328→    transition: all 0.2s ease;
329→    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.3);
330→    display: inline-flex;
331→    align-items: center;
332→}
333→
334→.dashboard-prompt-write-btn:hover {
335→    background: var(--accent-amber-hover, #d97706);
336→    transform: translateY(-1px);
337→    box-shadow: 0 4px 12px rgba(245, 158, 11, 0.35);
338→}
339→
340→.dashboard-prompt-write-btn:active {
341→    transform: translateY(0);
342→    box-shadow: 0 1px 4px rgba(245, 158, 11, 0.25);
343→}
344→
345→.dashboard-prompt-responses {
346→    display: flex;
347→    align-items: center;
348→    gap: 8px;
349→    cursor: pointer;
350→    padding: 4px 8px;
351→    margin: -4px -8px;
352→    border-radius: 8px;
353→    transition: background 0.15s ease;
354→    min-width: 0;
355→}
356→
357→.dashboard-prompt-responses:hover {
358→    background: var(--bg-hover, #ebebeb);
359→}
360→
361→.dashboard-prompt-avatars {
362→    display: flex;
363→    align-items: center;
364→    gap: 4px;
365→    flex-shrink: 0;
366→}
367→
368→.dashboard-prompt-avatar-wrap {
369→    display: inline-flex;
370→    align-items: center;
371→    justify-content: center;
372→    border-radius: 50%;
373→    flex-shrink: 0;
374→}
375→
376→.dashboard-prompt-avatar-wrap.pr-ring-legend {
377→    border: 2px solid #FFD700;
378→    box-shadow:
379→        0 0 4px 1px rgba(255, 215, 0, 0.4),
380→        0 0 8px 2px rgba(255, 215, 0, 0.25);
381→    animation: pr-glow-legend 2s ease-in-out infinite alternate;
382→}
383→
384→.dashboard-prompt-avatar-wrap.pr-ring-og {
385→    border: 2px solid #9B59FF;
386→    box-shadow:
387→        0 0 4px 1px rgba(155, 89, 255, 0.4),
388→        0 0 8px 2px rgba(155, 89, 255, 0.25);
389→    animation: pr-glow-og 2s ease-in-out infinite alternate;
390→}
391→
392→.dashboard-prompt-avatar {
393→    width: 32px;
394→    height: 32px;
395→    border-radius: 50%;
396→    object-fit: cover;
397→    flex-shrink: 0;
398→}
399→
400→.dashboard-prompt-count {
401→    font-size: 12px;
402→    color: var(--text-secondary, #a1a1aa);
403→}
404→
405→/* ─── Mobile ─── */
406→
407→@media (max-width: 480px) {
408→    .dashboard-briefing-body {
409→        padding: 12px 16px 14px;
410→    }
411→
412→    .dashboard-briefing-header {
413→        padding: 12px 16px 0;
414→    }
415→
416→    .dashboard-prompt-text {
417→        font-size: 15px;
418→    }
419→
420→    .recap-tiles-grid {
421→        grid-template-columns: repeat(2, 1fr);
422→    }
423→
424→    .recap-tile-value {
425→        font-size: 18px;
426→    }
427→
428→    .recap-tile-micro {
429→        font-size: 9px;
430→    }
431→}
432→
433→/* ─── Dark mode ─── */
434→
435→[data-theme="dark"] .dashboard-briefing-toggle:hover {
436→    background: rgba(255, 255, 255, 0.08);
437→}
438→
439→[data-theme="dark"] .dashboard-prompt-write-btn {
440→    background: var(--accent-amber, #f59e0b);
441→    color: #1a1a1a;
442→    box-shadow: 0 2px 8px rgba(245, 158, 11, 0.2);
443→}
444→
445→[data-theme="dark"] .dashboard-prompt-write-btn:hover {
446→    background: var(--accent-amber-hover, #d97706);
447→    box-shadow: 0 4px 12px rgba(245, 158, 11, 0.25);
448→}
449→
450→[data-theme="dark"] .recap-tile {
451→    background: var(--bg-secondary, #1e1e1e);
452→}
453→
454→[data-theme="dark"] .recap-tile:hover {
455→    background: var(--bg-hover, #2a2a2a);
456→}
457→
458→[data-theme="dark"] .recap-best-post {
459→    background: linear-gradient(135deg, rgba(245, 158, 11, 0.12) 0%, rgba(245, 158, 11, 0.04) 100%);
460→    border-color: rgba(245, 158, 11, 0.2);
461→}
462→
463→[data-theme="dark"] .dashboard-prompt-responses:hover {
464→    background: rgba(255, 255, 255, 0.06);
465→}
466→
467→/* ─── Prompt Responses Modal ─── */
468→
469→.prompt-responses-overlay {
470→    position: fixed;
471→    inset: 0;
472→    background: rgba(0, 0, 0, 0.4);
473→    backdrop-filter: blur(4px);
474→    display: flex;
475→    align-items: center;
476→    justify-content: center;
477→    z-index: 1000;
478→    padding: 20px;
479→}
480→
481→.prompt-responses-modal {
482→    background: var(--bg-elevated, #ffffff);
483→    border: 1px solid var(--border-card, #e5e5e5);
484→    border-radius: 16px;
485→    box-shadow: var(--shadow-modal, 0 8px 32px rgba(0, 0, 0, 0.12));
486→    width: 100%;
487→    max-width: 440px;
488→    max-height: 80vh;
489→    display: flex;
490→    flex-direction: column;
491→    overflow: hidden;
492→}
493→
494→.prompt-responses-header {
495→    display: flex;
496→    align-items: flex-start;
497→    justify-content: space-between;
498→    padding: 18px 20px 14px;
499→    border-bottom: 1px solid var(--border-card, #e5e5e5);
500→    gap: 12px;
501→}
502→
503→.prompt-responses-header-text {
504→    display: flex;
505→    flex-direction: column;
506→    gap: 4px;
507→    min-width: 0;
508→}
509→
510→.prompt-responses-title {
511→    font-family: 'Playfair Display', serif;
512→    font-size: 16px;
513→    font-weight: 600;
514→    color: var(--text-heading, #1a1a1a);
515→    margin: 0;
516→}
517→
518→.prompt-responses-prompt {
519→    font-family: 'Lora', serif;
520→    font-size: 12.5px;
521→    color: var(--text-secondary, #a1a1aa);
522→    margin: 0;
523→    line-height: 1.4;
524→    font-style: italic;
525→}
526→
527→.prompt-responses-close {
528→    background: none;
529→    border: none;
530→    cursor: pointer;
531→    color: var(--text-secondary, #a1a1aa);
532→    padding: 4px;
533→    border-radius: 6px;
534→    display: flex;
535→    align-items: center;
536→    justify-content: center;
537→    flex-shrink: 0;
538→    transition: background 0.15s ease, color 0.15s ease;
539→}
540→
541→.prompt-responses-close:hover {
542→    background: rgba(0, 0, 0, 0.05);
543→    color: var(--text-primary, #1a1a1a);
544→}
545→
546→.prompt-responses-list {
547→    overflow-y: auto;
548→    padding: 8px 12px 12px;
549→    display: flex;
550→    flex-direction: column;
551→    gap: 4px;
552→}
553→
554→.prompt-response-card {
555→    display: flex;
556→    flex-direction: column;
557→    gap: 6px;
558→    padding: 12px 14px;
559→    border-radius: 10px;
560→    cursor: pointer;
561→    transition: background 0.15s ease;
562→}
563→
564→.prompt-response-card:hover {
565→    background: var(--bg-hover, #f5f5f5);
566→}
567→
568→.prompt-response-author {
569→    display: flex;
570→    align-items: center;
571→    gap: 8px;
572→}
573→
574→.prompt-response-avatar-wrap {
575→    display: inline-flex;
576→    align-items: center;
577→    justify-content: center;
578→    border-radius: 50%;
579→    flex-shrink: 0;
580→}
581→
582→.prompt-response-avatar-wrap.pr-ring-legend {
583→    border: 2px solid #FFD700;
584→    box-shadow:
585→        0 0 6px 1px rgba(255, 215, 0, 0.5),
586→        0 0 12px 2px rgba(255, 215, 0, 0.35),
587→        0 0 20px 4px rgba(255, 215, 0, 0.2);
588→    animation: pr-glow-legend 2s ease-in-out infinite alternate;
589→}
590→
591→.prompt-response-avatar-wrap.pr-ring-og {
592→    border: 2px solid #9B59FF;
593→    box-shadow:
594→        0 0 6px 1px rgba(155, 89, 255, 0.5),
595→        0 0 12px 2px rgba(155, 89, 255, 0.35),
596→        0 0 20px 4px rgba(155, 89, 255, 0.2);
597→    animation: pr-glow-og 2s ease-in-out infinite alternate;
598→}
599→
600→@keyframes pr-glow-legend {
601→    from {
602→        box-shadow:
603→            0 0 6px 1px rgba(255, 215, 0, 0.5),
604→            0 0 12px 2px rgba(255, 215, 0, 0.35),
605→            0 0 20px 4px rgba(255, 215, 0, 0.2);
606→    }
607→    to {
608→        box-shadow:
609→            0 0 8px 2px rgba(255, 215, 0, 0.6),
610→            0 0 16px 4px rgba(255, 215, 0, 0.4),
611→            0 0 24px 6px rgba(255, 215, 0, 0.25);
612→    }
613→}
614→
615→@keyframes pr-glow-og {
616→    from {
617→        box-shadow:
618→            0 0 6px 1px rgba(155, 89, 255, 0.5),
619→            0 0 12px 2px rgba(155, 89, 255, 0.35),
620→            0 0 20px 4px rgba(155, 89, 255, 0.2);
621→    }
622→    to {
623→        box-shadow:
624→            0 0 8px 2px rgba(155, 89, 255, 0.6),
625→            0 0 16px 4px rgba(155, 89, 255, 0.4),
626→            0 0 24px 6px rgba(155, 89, 255, 0.25);
627→    }
628→}
629→
630→.prompt-response-avatar {
631→    width: 32px;
632→    height: 32px;
633→    border-radius: 50%;
634→    border: none;
635→    object-fit: cover;
636→    display: block;
637→}
638→
639→.prompt-response-name {
640→    font-family: 'Outfit', sans-serif;
641→    font-size: 13px;
642→    font-weight: 600;
643→    color: var(--text-primary, #1a1a1a);
644→}
645→
646→.prompt-response-title {
647→    font-family: 'Lora', serif;
648→    font-size: 14px;
649→    color: var(--text-primary, #1a1a1a);
650→    line-height: 1.4;
651→    margin: 0;
652→    display: -webkit-box;
653→    -webkit-line-clamp: 2;
654→    -webkit-box-orient: vertical;
655→    overflow: hidden;
656→}
657→
658→.prompt-response-time {
659→    font-family: 'Outfit', sans-serif;
660→    font-size: 11px;
661→    color: var(--text-muted, #9ca3af);
662→}
663→
664→/* ─── See More Button ─── */
665→
666→.prompt-responses-see-more {
667→    display: flex;
668→    align-items: center;
669→    justify-content: center;
670→    width: 100%;
671→    padding: 10px;
672→    margin-top: 4px;
673→    border: none;
674→    border-radius: 8px;
675→    background: var(--bg-secondary, #f5f5f5);
676→    color: var(--text-secondary, #a1a1aa);
677→    font-family: 'Outfit', sans-serif;
678→    font-size: 13px;
679→    font-weight: 500;
680→    cursor: pointer;
681→    transition: background 0.15s ease, color 0.15s ease;
682→    min-height: 38px;
683→}
684→
685→.prompt-responses-see-more:hover:not(:disabled) {
686→    background: var(--bg-hover, #ebebeb);
687→    color: var(--text-primary, #1a1a1a);
688→}
689→
690→.prompt-responses-see-more:disabled {
691→    cursor: default;
692→    opacity: 0.7;
693→}
694→
695→/* ─── Modal Mobile ─── */
696→
697→@media (max-width: 480px) {
698→    .prompt-responses-overlay {
699→        padding: 12px;
700→        align-items: flex-end;
701→    }
702→
703→    .prompt-responses-modal {
704→        max-height: 70vh;
705→        border-radius: 16px 16px 12px 12px;
706→    }
707→}
708→
