/* ─── Dashboard Briefing — Morning Digest ─── */

.dashboard-briefing {
    border-top: 2px solid var(--accent-amber);
    width: 100%;
    margin-bottom: 16px;
    overflow: hidden;
    padding: 0;
}

/* ─── Header ─── */

.dashboard-briefing-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 20px 24px 0;
}

.dashboard-briefing-header-left {
    display: flex;
    align-items: center;
    gap: 10px;
}

.dashboard-briefing-title {
    font-family: 'Playfair Display', serif;
    font-size: 16px;
    font-weight: 600;
    color: var(--text-primary, #1a1a1a);
    margin: 0;
}

.dashboard-briefing-date {
    font-family: 'Outfit', sans-serif;
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
    font-weight: 400;
}

.dashboard-briefing-toggle {
    background: none;
    border: none;
    cursor: pointer;
    color: var(--text-secondary, #a1a1aa);
    padding: 4px;
    border-radius: 6px;
    display: flex;
    align-items: center;
    justify-content: center;
    transition: background 0.15s ease, color 0.15s ease, transform 0.2s ease;
}

.dashboard-briefing-toggle:hover {
    background: rgba(0, 0, 0, 0.05);
    color: var(--text-primary, #1a1a1a);
}

.dashboard-briefing-toggle.is-collapsed {
    transform: rotate(-90deg);
}

/* ─── Content (stacked layout) ─── */

.dashboard-briefing-body {
    display: flex;
    flex-direction: column;
    padding: 14px 24px 20px;
    gap: 0;
}

/* ─── Divider ─── */

.dashboard-divider {
    height: 1px;
    background: var(--border-card);
    margin: 14px 0;
}

/* ─── Recap Section ─── */

.dashboard-recap-v2 {
    display: flex;
    flex-direction: column;
    gap: 14px;
}

.recap-encouragement {
    font-family: 'Lora', serif;
    font-style: italic;
    font-size: 13.5px;
    color: var(--text-secondary, #a1a1aa);
    margin: 0;
    line-height: 1.5;
}

/* ─── Stat Tiles — Inline Row with Hairline Dividers ─── */

.recap-tiles-grid {
    display: flex;
    justify-content: space-around;
    align-items: center;
}

.recap-tile {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 2px;
    padding: 8px 16px;
    border-right: 1px solid var(--border-card, #e5e5e5);
    flex: 1;
}

.recap-tile:last-child {
    border-right: none;
}

.recap-tile-icon {
    color: var(--accent-amber, #f59e0b);
    opacity: 0.6;
    margin-bottom: 2px;
}

.recap-tile-value {
    font-family: 'Playfair Display', serif;
    font-size: 28px;
    font-weight: 700;
    color: var(--text-primary, #1a1a1a);
    font-variant-numeric: tabular-nums;
    line-height: 1.2;
}

.recap-tile-label {
    font-family: 'Outfit', sans-serif;
    font-size: 10px;
    text-transform: uppercase;
    color: var(--text-muted, #9ca3af);
    letter-spacing: 0.8px;
}

/* ─── Best Post — Minimal Inline ─── */

.recap-best-post {
    display: flex;
