    min-width: 0;
}

.dashboard-prompt-responses:hover {
    background: var(--bg-hover, #ebebeb);
}

.dashboard-prompt-avatars {
    display: flex;
    align-items: center;
    flex-shrink: 0;
}

.dashboard-prompt-avatar-wrap {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 50%;
    flex-shrink: 0;
    margin-left: -6px;
}

.dashboard-prompt-avatar-wrap:first-child {
    margin-left: 0;
}

.dashboard-prompt-avatar-wrap.pr-ring-legend {
    border: 2px solid #FFD700;
    box-shadow:
        0 0 4px 1px rgba(255, 215, 0, 0.4),
        0 0 8px 2px rgba(255, 215, 0, 0.25);
    animation: pr-glow-legend 2s ease-in-out infinite alternate;
}

.dashboard-prompt-avatar-wrap.pr-ring-og {
    border: 2px solid #9B59FF;
    box-shadow:
        0 0 4px 1px rgba(155, 89, 255, 0.4),
        0 0 8px 2px rgba(155, 89, 255, 0.25);
    animation: pr-glow-og 2s ease-in-out infinite alternate;
}

.dashboard-prompt-avatar {
    width: 32px;
    height: 32px;
    border-radius: 50%;
    object-fit: cover;
    flex-shrink: 0;
}

.dashboard-prompt-count {
    font-size: 12px;
    color: var(--text-secondary, #a1a1aa);
}

/* ─── Mobile ─── */

@media (max-width: 480px) {
    .dashboard-briefing-body {
        padding: 12px 16px 14px;
    }

    .dashboard-briefing-header {
        padding: 14px 16px 0;
    }

    .dashboard-prompt-text {
        font-size: 17px;
    }

    .recap-tiles-grid {
        display: grid;
        grid-template-columns: repeat(2, 1fr);
        gap: 0;
    }

    .recap-tile {
        border-right: none;
        border-bottom: 1px solid var(--border-card, #e5e5e5);
        padding: 10px 8px;
    }

    .recap-tile:nth-child(odd) {
        border-right: 1px solid var(--border-card, #e5e5e5);
    }

    .recap-tile:nth-last-child(-n+2) {
        border-bottom: none;
    }

    .recap-tile-value {
        font-size: 22px;
    }
}

/* ─── Dark mode ─── */

[data-theme="dark"] .dashboard-briefing {
    background: rgba(255, 255, 255, 0.02);
}

[data-theme="dark"] .dashboard-briefing-toggle:hover {
    background: rgba(255, 255, 255, 0.08);
}

[data-theme="dark"] .dashboard-prompt-write-btn {
    border-color: var(--accent-amber, #f59e0b);
    color: var(--accent-amber, #f59e0b);
    background: transparent;
}

[data-theme="dark"] .dashboard-prompt-write-btn:hover {
    background: var(--accent-amber, #f59e0b);
    color: #1a1a1a;
}

[data-theme="dark"] .dashboard-prompt-responses:hover {
    background: rgba(255, 255, 255, 0.06);
}

[data-theme="dark"] .recap-community-clickable:hover {
    background: rgba(255, 255, 255, 0.06);
}

